app.post('/login', (req, res) => {
  const { username, password, client_id, redirect_uri, state, scope } = req.body;

  const user = users[username];
  if (!user || user.password !== password) {
    return res.status(401).send('Invalid username or password');
  }

  const authCode = generateRandomString();
  const expiresAt = Date.now() + 10 * 60 * 1000;

  authorizationCodes.set(authCode, {
    client_id,
    redirect_uri,
    user_id: user.id,
    username: user.username,
    scope: scope || '',
    expiresAt
  });

  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', authCode);
  if (state) {
    redirectUrl.searchParams.append('state', state);
  }

  res.redirect(redirectUrl.toString());
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret, refresh_token } = req.body;

  if (grant_type === 'authorization_code') {
    if (!code || !redirect_uri || !client_id || !client_secret) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
    }

    const client = clients[client_id];
    if (!client || client.client_secret !== client_secret) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }

    const authCodeData = authorizationCodes.get(code);
    if (!authCodeData) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
    }

    if (authCodeData.expiresAt < Date.now()) {
      authorizationCodes.delete(code);
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
    }

    if (authCodeData.client_id !== client_id || authCodeData.redirect_uri !== redirect_uri) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Client mismatch' });
    }

    authorizationCodes.delete(code);

    const accessToken = generateRandomString();
    const newRefreshToken = generateRandomString();
    const expiresIn = 3600;

    accessTokens.set(accessToken, {
      client_id,
      user_id: authCodeData.user_id,
      username: authCodeData.username,
      scope: authCodeData.scope,
      expiresAt: Date.now() + expiresIn * 1000
    });

    refreshTokens.set(newRefreshToken, {
      client_id,
      user_id: authCodeData.user_id,
      username: authCodeData.username,
      scope: authCodeData.scope
    });

    return res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: expiresIn,
      refresh_token: newRefreshToken,
      scope: authCodeData.scope
    });

  } else if (grant_type === 'refresh_token') {
    if (!refresh_token || !client_id || !client_secret) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
    }

    const client = clients[client_id];
    if (!client || client.client_secret !== client_secret) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }

    const refreshTokenData = refreshTokens.get(refresh_token);
    if (!refreshTokenData || refreshTokenData.client_id !== client_id) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid refresh token' });
    }

    const accessToken = generateRandomString();
    const expiresIn = 3600;

    accessTokens.set(accessToken, {
      client_id,
      user_id: refreshTokenData.user_id,
      username: refreshTokenData.username,
      scope: refreshTokenData.scope,
      expiresAt: Date.now() + expiresIn * 1000
    });

    return res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: expiresIn,
      scope: refreshTokenData.scope
    });

  } else {
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Grant type not supported' });
  }
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Missing or invalid authorization header' });
  }

  const token = authHeader.substring(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Invalid access token' });
  }

  if (tokenData.expiresAt < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Access token expired' });
  }

  return res.json({
    sub: tokenData.user_id,
    username: tokenData.username,
    scope: tokenData.scope
  });
});

app.post('/revoke', (req, res) => {
  const { token, token_type_hint, client_id, client_secret } = req.body;

  if (!token || !client_id || !client_secret) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (token_type_hint === 'refresh_token' || refreshTokens.has(token)) {
    refreshTokens.delete(token);
  } else {
    accessTokens.delete(token);
  }

  return res.status(200).send();
});

